        for token in ("pricing", "price", "cost", "plan", "plans"):
            if token in lowered:
                has_pricing_keyword = True
                break
        if not has_pricing_keyword:
            return ("Ruhu pricing plans " + text).strip() or "Ruhu pricing plans"
        return text or "Ruhu pricing plans"
