        "describe", "explain", "what is", "learn about", "tell me about",
        "talk about", "product overview", "platform overview",
    )
    overview_match = False
    for phrase in overview_phrases:
        if phrase in lowered:
            overview_match = True
            break
    if mentions_ruhu and overview_match:
        return "Ruhu product overview"
    build_tokens = (
        "build", "builder", "workflow", "workflows", "automation", "automations",
        "trigger", "triggers", "condition", "conditions", "integration", "integrations",
        "api", "webhook", "system", "agent", "agents",
    )
    feature_tokens = ("feature", "features", "capability", "capabilities", "use case", "use cases")
    build_match = False
    for token in build_tokens:
        if token in lowered:
            build_match = True
            break
    if build_match:
        prefix = "How to build AI agents and workflows on Ruhu"
        return (prefix + " " + text).strip() if text else prefix
    feature_match = False
    for token in feature_tokens:
        if token in lowered:
            feature_match = True
            break
    if feature_match:
        prefix = "Ruhu product features and capabilities"
        return (prefix + " " + text).strip() if text else prefix
    detail_match = False
    for phrase in (
        "what else can you tell me",
        "what else can i do",
        "what can you do for me",
        "tell me more",
        "go into detail",
        "more detail",
        "specific details",
    ):
        if phrase in lowered:
            detail_match = True
            break
    if detail_match:
